-- Orqena Macrofase 2: additive commercial platform foundation.
CREATE TYPE "PlatformRole" AS ENUM ('PLATFORM_OWNER','PLATFORM_ADMIN','PLATFORM_SUPPORT','PLATFORM_ANALYST');
CREATE TYPE "PlatformAccountStatus" AS ENUM ('ACTIVE','SUSPENDED','REVOKED');
CREATE TYPE "EntitlementValueType" AS ENUM ('BOOLEAN','INTEGER','DECIMAL','STRING','ENUM');
CREATE TYPE "SubscriptionStatus" AS ENUM ('TRIALING','ACTIVE','PAST_DUE','PAUSED','CANCELED','EXPIRED');
CREATE TYPE "InvitationStatus" AS ENUM ('PENDING','ACCEPTED','EXPIRED','REVOKED','REJECTED');
CREATE TYPE "TeamState" AS ENUM ('ACTIVE','ARCHIVED');
CREATE TYPE "ScopeType" AS ENUM ('COMPANY','OWN','ASSIGNED','TEAM','SELECTED_WORKS','SELECTED_CLIENTS');
CREATE TYPE "PermissionOverrideEffect" AS ENUM ('GRANT','DENY');
CREATE TYPE "SupportAccessStatus" AS ENUM ('ACTIVE','EXPIRED','REVOKED','CLOSED');
CREATE TYPE "CompanyCommercialStatus" AS ENUM ('ACTIVE','SUSPENDED','READ_ONLY');
ALTER TYPE "MembershipStatus" ADD VALUE 'revoked';

ALTER TABLE "Company" ADD COLUMN "commercialStatus" "CompanyCommercialStatus" NOT NULL DEFAULT 'ACTIVE', ADD COLUMN "demoExpiresAt" TIMESTAMP(3), ADD COLUMN "demoScenarioKey" TEXT, ADD COLUMN "provisioningKey" TEXT;
ALTER TABLE "CompanyMembership" ADD COLUMN "invitedById" TEXT, ADD COLUMN "isDemo" BOOLEAN NOT NULL DEFAULT false, ADD COLUMN "lastActivityAt" TIMESTAMP(3), ADD COLUMN "origin" TEXT NOT NULL DEFAULT 'existing', ADD COLUMN "revokedAt" TIMESTAMP(3), ADD COLUMN "revokedReason" TEXT;
ALTER TABLE "User" ADD COLUMN "activeCompanyId" TEXT;

CREATE TABLE "PlatformAccount" ("id" TEXT NOT NULL,"userId" TEXT NOT NULL,"role" "PlatformRole" NOT NULL,"status" "PlatformAccountStatus" NOT NULL DEFAULT 'ACTIVE',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "PlatformAccount_pkey" PRIMARY KEY ("id"));
CREATE TABLE "MembershipPermissionOverride" ("id" TEXT NOT NULL,"membershipId" TEXT NOT NULL,"capabilityKey" TEXT NOT NULL,"effect" "PermissionOverrideEffect" NOT NULL,"scope" "ScopeType","changedById" TEXT,"reason" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "MembershipPermissionOverride_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Team" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"managerMembershipId" TEXT,"state" "TeamState" NOT NULL DEFAULT 'ACTIVE',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,"archivedAt" TIMESTAMP(3),CONSTRAINT "Team_pkey" PRIMARY KEY ("id"));
CREATE TABLE "TeamMembership" ("id" TEXT NOT NULL,"teamId" TEXT NOT NULL,"membershipId" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "TeamMembership_pkey" PRIMARY KEY ("id"));
CREATE TABLE "ScopeAssignment" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"membershipId" TEXT NOT NULL,"capabilityKey" TEXT NOT NULL,"scope" "ScopeType" NOT NULL,"teamId" TEXT,"entityType" TEXT,"entityId" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "ScopeAssignment_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Plan" ("id" TEXT NOT NULL,"key" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT NOT NULL,"audience" TEXT NOT NULL,"commercialState" TEXT NOT NULL DEFAULT 'internal',"currency" TEXT,"period" TEXT,"price" DECIMAL(12,2),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Plan_pkey" PRIMARY KEY ("id"));
CREATE TABLE "PlanEntitlement" ("id" TEXT NOT NULL,"planId" TEXT NOT NULL,"key" TEXT NOT NULL,"type" "EntitlementValueType" NOT NULL,"value" JSONB NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "PlanEntitlement_pkey" PRIMARY KEY ("id"));
CREATE TABLE "CompanyEntitlementOverride" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"key" TEXT NOT NULL,"type" "EntitlementValueType" NOT NULL,"value" JSONB NOT NULL,"startsAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"endsAt" TIMESTAMP(3),"reason" TEXT NOT NULL,"active" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "CompanyEntitlementOverride_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Subscription" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"planId" TEXT NOT NULL,"status" "SubscriptionStatus" NOT NULL DEFAULT 'TRIALING',"provider" TEXT NOT NULL DEFAULT 'local',"externalCustomerId" TEXT,"externalSubscriptionId" TEXT,"startedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"trialEndsAt" TIMESTAMP(3),"currentPeriodStart" TIMESTAMP(3) NOT NULL,"currentPeriodEnd" TIMESTAMP(3) NOT NULL,"cancelAtPeriodEnd" BOOLEAN NOT NULL DEFAULT false,"canceledAt" TIMESTAMP(3),"metadata" JSONB,"scheduledPlanKey" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Subscription_pkey" PRIMARY KEY ("id"));
CREATE TABLE "SubscriptionHistory" ("id" TEXT NOT NULL,"subscriptionId" TEXT NOT NULL,"action" TEXT NOT NULL,"fromPlanKey" TEXT,"toPlanKey" TEXT,"fromStatus" "SubscriptionStatus","toStatus" "SubscriptionStatus","reason" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "SubscriptionHistory_pkey" PRIMARY KEY ("id"));
CREATE TABLE "UsageRecord" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"metric" TEXT NOT NULL,"quantity" DECIMAL(18,4) NOT NULL,"periodStart" TIMESTAMP(3) NOT NULL,"periodEnd" TIMESTAMP(3) NOT NULL,"idempotencyKey" TEXT NOT NULL,"origin" TEXT NOT NULL,"reference" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "UsageRecord_pkey" PRIMARY KEY ("id"));
CREATE TABLE "Invitation" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"emailNormalized" TEXT NOT NULL,"role" "CompanyRole" NOT NULL,"status" "InvitationStatus" NOT NULL DEFAULT 'PENDING',"tokenHash" TEXT NOT NULL,"inviterId" TEXT NOT NULL,"permissionTemplate" JSONB,"teamIds" JSONB,"expiresAt" TIMESTAMP(3) NOT NULL,"acceptedAt" TIMESTAMP(3),"rejectedAt" TIMESTAMP(3),"revokedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "Invitation_pkey" PRIMARY KEY ("id"));
CREATE TABLE "AuditLog" ("id" TEXT NOT NULL,"companyId" TEXT,"platformActorId" TEXT,"userActorId" TEXT,"action" TEXT NOT NULL,"targetType" TEXT NOT NULL,"targetId" TEXT,"metadata" JSONB,"reason" TEXT,"ipHash" TEXT,"userAgent" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "AuditLog_pkey" PRIMARY KEY ("id"));
CREATE TABLE "SupportAccessGrant" ("id" TEXT NOT NULL,"companyId" TEXT NOT NULL,"platformAccountId" TEXT NOT NULL,"reason" TEXT NOT NULL,"ticketReference" TEXT,"capabilityKeys" JSONB NOT NULL,"status" "SupportAccessStatus" NOT NULL DEFAULT 'ACTIVE',"startsAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"expiresAt" TIMESTAMP(3) NOT NULL,"endedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "SupportAccessGrant_pkey" PRIMARY KEY ("id"));

CREATE UNIQUE INDEX "Company_provisioningKey_key" ON "Company"("provisioningKey");
CREATE UNIQUE INDEX "PlatformAccount_userId_key" ON "PlatformAccount"("userId"); CREATE INDEX "PlatformAccount_role_status_idx" ON "PlatformAccount"("role","status");
CREATE UNIQUE INDEX "MembershipPermissionOverride_membershipId_capabilityKey_key" ON "MembershipPermissionOverride"("membershipId","capabilityKey"); CREATE INDEX "MembershipPermissionOverride_capabilityKey_effect_idx" ON "MembershipPermissionOverride"("capabilityKey","effect");
CREATE UNIQUE INDEX "Team_companyId_name_key" ON "Team"("companyId","name"); CREATE INDEX "Team_companyId_state_idx" ON "Team"("companyId","state");
CREATE UNIQUE INDEX "TeamMembership_teamId_membershipId_key" ON "TeamMembership"("teamId","membershipId"); CREATE INDEX "TeamMembership_membershipId_idx" ON "TeamMembership"("membershipId");
CREATE INDEX "ScopeAssignment_companyId_membershipId_capabilityKey_idx" ON "ScopeAssignment"("companyId","membershipId","capabilityKey"); CREATE INDEX "ScopeAssignment_entityType_entityId_idx" ON "ScopeAssignment"("entityType","entityId");
CREATE UNIQUE INDEX "Plan_key_key" ON "Plan"("key"); CREATE UNIQUE INDEX "PlanEntitlement_planId_key_key" ON "PlanEntitlement"("planId","key"); CREATE INDEX "PlanEntitlement_key_idx" ON "PlanEntitlement"("key");
CREATE UNIQUE INDEX "CompanyEntitlementOverride_companyId_key_key" ON "CompanyEntitlementOverride"("companyId","key"); CREATE INDEX "CompanyEntitlementOverride_companyId_active_endsAt_idx" ON "CompanyEntitlementOverride"("companyId","active","endsAt");
CREATE INDEX "Subscription_companyId_status_idx" ON "Subscription"("companyId","status"); CREATE INDEX "Subscription_currentPeriodEnd_idx" ON "Subscription"("currentPeriodEnd"); CREATE INDEX "SubscriptionHistory_subscriptionId_createdAt_idx" ON "SubscriptionHistory"("subscriptionId","createdAt");
CREATE UNIQUE INDEX "UsageRecord_companyId_metric_idempotencyKey_key" ON "UsageRecord"("companyId","metric","idempotencyKey"); CREATE INDEX "UsageRecord_companyId_metric_periodStart_periodEnd_idx" ON "UsageRecord"("companyId","metric","periodStart","periodEnd");
CREATE UNIQUE INDEX "Invitation_tokenHash_key" ON "Invitation"("tokenHash"); CREATE INDEX "Invitation_companyId_status_idx" ON "Invitation"("companyId","status"); CREATE INDEX "Invitation_emailNormalized_status_idx" ON "Invitation"("emailNormalized","status"); CREATE INDEX "Invitation_expiresAt_idx" ON "Invitation"("expiresAt");
CREATE INDEX "AuditLog_companyId_createdAt_idx" ON "AuditLog"("companyId","createdAt"); CREATE INDEX "AuditLog_action_createdAt_idx" ON "AuditLog"("action","createdAt");
CREATE INDEX "SupportAccessGrant_companyId_status_expiresAt_idx" ON "SupportAccessGrant"("companyId","status","expiresAt"); CREATE INDEX "SupportAccessGrant_platformAccountId_status_expiresAt_idx" ON "SupportAccessGrant"("platformAccountId","status","expiresAt");

ALTER TABLE "User" ADD CONSTRAINT "User_activeCompanyId_fkey" FOREIGN KEY ("activeCompanyId") REFERENCES "Company"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "CompanyMembership" ADD CONSTRAINT "CompanyMembership_invitedById_fkey" FOREIGN KEY ("invitedById") REFERENCES "User"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "PlatformAccount" ADD CONSTRAINT "PlatformAccount_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "MembershipPermissionOverride" ADD CONSTRAINT "MembershipPermissionOverride_membershipId_fkey" FOREIGN KEY ("membershipId") REFERENCES "CompanyMembership"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "Team" ADD CONSTRAINT "Team_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "TeamMembership" ADD CONSTRAINT "TeamMembership_teamId_fkey" FOREIGN KEY ("teamId") REFERENCES "Team"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "TeamMembership" ADD CONSTRAINT "TeamMembership_membershipId_fkey" FOREIGN KEY ("membershipId") REFERENCES "CompanyMembership"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "ScopeAssignment" ADD CONSTRAINT "ScopeAssignment_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "ScopeAssignment" ADD CONSTRAINT "ScopeAssignment_membershipId_fkey" FOREIGN KEY ("membershipId") REFERENCES "CompanyMembership"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "ScopeAssignment" ADD CONSTRAINT "ScopeAssignment_teamId_fkey" FOREIGN KEY ("teamId") REFERENCES "Team"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "PlanEntitlement" ADD CONSTRAINT "PlanEntitlement_planId_fkey" FOREIGN KEY ("planId") REFERENCES "Plan"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "CompanyEntitlementOverride" ADD CONSTRAINT "CompanyEntitlementOverride_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "Subscription" ADD CONSTRAINT "Subscription_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "Subscription" ADD CONSTRAINT "Subscription_planId_fkey" FOREIGN KEY ("planId") REFERENCES "Plan"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "SubscriptionHistory" ADD CONSTRAINT "SubscriptionHistory_subscriptionId_fkey" FOREIGN KEY ("subscriptionId") REFERENCES "Subscription"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "UsageRecord" ADD CONSTRAINT "UsageRecord_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "Invitation" ADD CONSTRAINT "Invitation_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "Invitation" ADD CONSTRAINT "Invitation_inviterId_fkey" FOREIGN KEY ("inviterId") REFERENCES "User"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "AuditLog" ADD CONSTRAINT "AuditLog_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "AuditLog" ADD CONSTRAINT "AuditLog_platformActorId_fkey" FOREIGN KEY ("platformActorId") REFERENCES "PlatformAccount"("id") ON DELETE SET NULL ON UPDATE CASCADE; ALTER TABLE "AuditLog" ADD CONSTRAINT "AuditLog_userActorId_fkey" FOREIGN KEY ("userActorId") REFERENCES "User"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "SupportAccessGrant" ADD CONSTRAINT "SupportAccessGrant_companyId_fkey" FOREIGN KEY ("companyId") REFERENCES "Company"("id") ON DELETE RESTRICT ON UPDATE CASCADE; ALTER TABLE "SupportAccessGrant" ADD CONSTRAINT "SupportAccessGrant_platformAccountId_fkey" FOREIGN KEY ("platformAccountId") REFERENCES "PlatformAccount"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
